def create_hero_svg(path, title, color, bullets):
    width, height = 1200, 630
    wrapped = textwrap.wrap(title, width=22)[:3]
    bullet_y = 290
    svg = [f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}" viewBox="0 0 {width} {height}" role="img" aria-label="{escape(title)}">']
    svg.append(f'''
<defs>
  <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%"><feDropShadow dx="0" dy="12" stdDeviation="18" flood-color="rgba(15,23,42,.28)"/></filter>
</defs>
<rect width="1200" height="630" rx="32" fill="#0f172a"/>
<circle cx="1030" cy="130" r="190" fill="{color}" opacity=".18"/>
<circle cx="1140" cy="40" r="120" fill="{color}" opacity=".12"/>
<rect x="56" y="56" width="1088" height="518" rx="28" fill="rgba(255,255,255,.04)" stroke="rgba(255,255,255,.08)"/>
<rect x="72" y="74" width="168" height="168" rx="32" fill="{color}" filter="url(#shadow)"/>
<text x="156" y="176" fill="#fff" font-size="78" font-family="Arial, Helvetica, sans-serif" font-weight="800" text-anchor="middle">{escape(title[0].upper())}</text>
<text x="270" y="112" fill="#93c5fd" font-size="26" font-family="Arial, Helvetica, sans-serif" font-weight="700">ПОЛНЫЙ ОБЗОР</text>
''')
    y=170
    for line in wrapped:
        svg.append(f'<text x="270" y="{y}" fill="#ffffff" font-size="54" font-family="Arial, Helvetica, sans-serif" font-weight="800">{escape(line)}</text>')
        y += 62
    for i, bullet in enumerate(bullets[:4]):
        by = bullet_y + i*68
        svg.append(f'<circle cx="294" cy="{by-10}" r="8" fill="{color}"/>')
        svg.append(f'<text x="320" y="{by}" fill="#e2e8f0" font-size="28" font-family="Arial, Helvetica, sans-serif">{escape(bullet)}</text>')
    svg.append('</svg>')
    path.write_text("\n".join(svg), encoding='utf-8')


def create_table_svg(path, current_name, color):
    width, height = 1200, 760
    rows = list(comparison_rows.items())
    svg = [f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}" viewBox="0 0 {width} {height}" role="img" aria-label="Сравнительная таблица {escape(current_name)}">']
    svg.append('<rect width="1200" height="760" rx="28" fill="#ffffff"/>')
    svg.append('<rect x="0" y="0" width="1200" height="82" rx="28" fill="#0f172a"/>')
    svg.append('<text x="34" y="52" fill="#ffffff" font-size="34" font-family="Arial, Helvetica, sans-serif" font-weight="800">Сравнение по открытым данным</text>')
    cols = [("Сервис", 20),("Пробный доступ / free", 190),("Устройства", 510),("Тарифы", 640),("Платформы", 880)]
    y0 = 106
    for title, x in cols:
        svg.append(f'<text x="{x}" y="{y0}" fill="#334155" font-size="18" font-family="Arial, Helvetica, sans-serif" font-weight="700">{escape(title)}</text>')
    y = 126
    svg.append(f'<line x1="20" y1="{y}" x2="1180" y2="{y}" stroke="#dbe3ef" stroke-width="1"/>')
    y += 18
    def add_wrapped(text, x, ytop, max_chars, font_size=16, weight='400', fill='#0f172a'):
        for i, line in enumerate(textwrap.wrap(text, width=max_chars)[:4]):
            yy = ytop + 24 + i*(font_size+6)
            svg.append(f'<text x="{x}" y="{yy}" fill="{fill}" font-size="{font_size}" font-family="Arial, Helvetica, sans-serif" font-weight="{weight}">{escape(line)}</text>')
    for name, data in rows:
        fill = '#eff6ff' if name == current_name else '#ffffff'
        stroke = color if name == current_name else '#e2e8f0'
        svg.append(f'<rect x="18" y="{y}" width="1164" height="86" rx="18" fill="{fill}" stroke="{stroke}" stroke-width="2"/>')
        add_wrapped(name, 34, y, 16, 18, '800')
        add_wrapped(data['offer'], 204, y, 32, 15, '400', '#334155')
        add_wrapped(data['devices'], 524, y, 16, 16, '700', '#0f172a')
        add_wrapped(data['pricing'], 654, y, 24, 15, '400', '#334155')
        add_wrapped(data['platforms'], 894, y, 32, 15, '400', '#334155')
        y += 96
    svg.append('</svg>')
    path.write_text("\n".join(svg), encoding='utf-8')


def create_connections_svg(path):
    width, height = 1200, 540
    maxv = max(v for _,v,_ in connections)
    svg = [f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}" viewBox="0 0 {width} {height}" role="img" aria-label="График количества одновременных устройств по открытым данным">']
    svg.append('<rect width="1200" height="540" rx="28" fill="#ffffff"/>')
    svg.append('<text x="34" y="52" fill="#0f172a" font-size="34" font-family="Arial, Helvetica, sans-serif" font-weight="800">Одновременные подключения по открытым данным</text>')
    svg.append('<text x="34" y="84" fill="#64748b" font-size="18" font-family="Arial, Helvetica, sans-serif">Показаны только сервисы, где число устройств явно указано на открытых страницах</text>')
    base_y, left, chart_w, chart_h = 460, 120, 960, 300
    for i in range(0, 11, 2):
        y = base_y - chart_h * i/maxv
        svg.append(f'<line x1="{left}" y1="{y}" x2="{left+chart_w}" y2="{y}" stroke="#e2e8f0" stroke-width="1"/>')
        svg.append(f'<text x="{left-18}" y="{y+6}" fill="#64748b" font-size="16" text-anchor="end" font-family="Arial, Helvetica, sans-serif">{i}</text>')
    x = left + 80
    for name,val,color in connections:
        bar_w = 180
        h = chart_h * val/maxv
        y = base_y - h
        svg.append(f'<rect x="{x}" y="{y}" width="{bar_w}" height="{h}" rx="22" fill="{color}"/>')
        svg.append(f'<text x="{x+bar_w/2}" y="{y-16}" fill="#0f172a" font-size="22" text-anchor="middle" font-family="Arial, Helvetica, sans-serif" font-weight="800">{val}</text>')
        for j, line in enumerate(textwrap.wrap(name, width=12)[:2]):
            svg.append(f'<text x="{x+bar_w/2}" y="{base_y+34 + j*22}" fill="#334155" font-size="18" text-anchor="middle" font-family="Arial, Helvetica, sans-serif">{escape(line)}</text>')
        x += bar_w + 120
    svg.append('</svg>')
    path.write_text("\n".join(svg), encoding='utf-8')

